index.styles:
* { margin: 0; padding: 0; box-sizing: border-box; }
    body { font-family: -apple-system, BlinkMacSystemFont, 'Hiragino Kaku Gothic ProN', 'Hiragino Sans', Meiryo, sans-serif; color: #333; line-height: 1.8; background: #feffff; }
    .hero { background: #333; color: #feffff; padding: 80px 20px 100px; text-align: center; position: relative; overflow: hidden; }
    .hero::before { content: ''; position: absolute; inset: 0; background: linear-gradient(135deg, rgba(19,149,186,0.22) 0%, transparent 55%, rgba(21,183,136,0.1) 100%); }
    .hero-inner { position: relative; max-width: 720px; margin: 0 auto; }
    .hero-icon { width: 96px; height: 96px; border-radius: 22%; box-shadow: 0 8px 32px rgba(19,149,186,0.35); margin: 0 auto 1.25rem; display: block; }
    .hero .eyebrow { display: inline-block; background: rgba(255,255,255,0.1); border: 1px solid rgba(255,255,255,0.2); border-radius: 100px; padding: 6px 18px; font-size: 0.8rem; margin-bottom: 1.25rem; color: #7ec8e3; }
    .hero h1 { font-size: 2.6rem; font-weight: 800; margin-bottom: 0.3rem; }
    .hero h1 small { font-size: 1.15rem; font-weight: 400; display: block; color: #15b788; margin-top: 0.3rem; }
    .hero .desc { font-size: 1rem; opacity: 0.9; max-width: 560px; margin: 1.5rem auto 0; }
    .compare-hero { display: flex; justify-content: center; gap: 16px; margin-top: 2.5rem; flex-wrap: wrap; align-items: stretch; }
    .compare-box { flex: 1; min-width: 140px; max-width: 220px; border-radius: 14px; padding: 20px 16px; text-align: center; }
    .compare-box.before { background: rgba(255,255,255,0.06); border: 1px dashed rgba(255,255,255,0.25); opacity: 0.85; }
    .compare-box.after { background: rgba(19,149,186,0.25); border: 2px solid #1395ba; }
    .compare-box .label { font-size: 0.7rem; letter-spacing: 0.08em; opacity: 0.7; margin-bottom: 8px; }
    .compare-box .emoji { font-size: 2rem; margin-bottom: 6px; }
    .compare-box .text { font-size: 0.9rem; font-weight: 600; line-height: 1.5; }
    .compare-arrow { display: flex; align-items: center; font-size: 1.5rem; color: #1395ba; font-weight: 700; }
    section { padding: 80px 20px; }
    section:nth-child(even) { background: #f8f9fa; }
    .container { max-width: 800px; margin: 0 auto; }
    .section-title { font-size: 1.6rem; font-weight: 700; text-align: center; margin-bottom: 0.5rem; }
    .section-subtitle { text-align: center; color: #888; font-size: 0.95rem; margin-bottom: 3rem; }
    .insight-card { background: #fff; border-radius: 16px; padding: 28px 32px; border: 1px solid rgba(19,149,186,0.15); box-shadow: 0 2px 12px rgba(0,0,0,0.04); text-align: center; margin-bottom: 2rem; }
    .insight-card p { font-size: 1.05rem; font-weight: 600; color: #444; }
    .insight-card .stat { font-size: 2rem; font-weight: 800; color: #1395ba; display: block; margin-bottom: 0.5rem; }
    .pain-columns { display: grid; grid-template-columns: 1fr 1fr; gap: 24px; margin-bottom: 2rem; }
    .pain-column { background: #fff; border-radius: 14px; padding: 24px; border: 1px solid #eee; }
    .pain-column h3 { font-size: 1rem; margin-bottom: 1rem; padding-bottom: 0.5rem; border-bottom: 2px solid #eee; }
    .pain-column.applicant h3 { color: #1395ba; border-bottom-color: rgba(19,149,186,0.3); }
    .pain-column.scrivener h3 { color: #15b788; border-bottom-color: rgba(21,183,136,0.3); }
    .pain-list { display: grid; gap: 12px; }
    .pain-item { padding: 14px 16px; border-radius: 10px; background: #f8f9fa; border-left: 3px solid #ccc; }
    .pain-column.applicant .pain-item { border-left-color: #1395ba; }
    .pain-column.scrivener .pain-item { border-left-color: #15b788; }
    .pain-item strong { display: block; color: #555; margin-bottom: 4px; font-size: 0.9rem; }
    .pain-item span { font-size: 0.85rem; color: #777; }
    .solution-banner { background: linear-gradient(135deg, #e8f4f8 0%, #eefaf5 100%); border-radius: 16px; padding: 28px 32px; text-align: center; border: 1px solid rgba(19,149,186,0.2); margin-bottom: 2rem; }
    .solution-banner p { font-size: 1.1rem; color: #333; font-weight: 700; line-height: 1.7; }
    .solution-banner .highlight { color: #1395ba; }
    .solution-paths { display: grid; grid-template-columns: 1fr 1fr; gap: 20px; }
    .solution-path { background: #fff; border-radius: 14px; padding: 28px 24px; border: 1px solid #eee; text-align: center; }
    .solution-path.applicant { border-top: 4px solid #1395ba; }
    .solution-path.scrivener { border-top: 4px solid #15b788; }
    .app-icon-md { width: 48px; height: 48px; border-radius: 22%; margin-bottom: 12px; }
    .solution-path h3 { font-size: 1rem; margin-bottom: 12px; }
    .solution-path ul { text-align: left; font-size: 0.85rem; color: #666; padding-left: 1.2rem; line-height: 1.7; }
    .solution-path .badge-free { display: inline-block; background: #1395ba; color: #fff; font-size: 0.75rem; font-weight: 700; padding: 4px 12px; border-radius: 100px; margin-top: 12px; }
    .solution-path .badge-pro { display: inline-block; background: #15b788; color: #fff; font-size: 0.75rem; font-weight: 700; padding: 4px 12px; border-radius: 100px; margin-top: 12px; }
    .legal-note { font-size: 0.8rem; color: #888; text-align: center; margin-top: 1.5rem; line-height: 1.7; }
    .flow-block { margin-bottom: 3rem; }
    .flow-block:last-child { margin-bottom: 0; }
    .flow-heading { display: flex; align-items: center; justify-content: center; gap: 10px; margin-bottom: 1.5rem; }
    .app-icon-sm { width: 40px; height: 40px; border-radius: 22%; }
    .flow-heading h3 { font-size: 1.1rem; }
    .flow-heading.applicant h3 { color: #1395ba; }
    .flow-heading.scrivener h3 { color: #15b788; }
    .steps { display: grid; grid-template-columns: repeat(auto-fit, minmax(160px, 1fr)); gap: 16px; }
    .step { background: #fff; border-radius: 12px; padding: 20px 16px; border: 1px solid #eee; text-align: center; }
    .step .num { display: inline-block; width: 28px; height: 28px; line-height: 28px; border-radius: 50%; background: #1395ba; color: #fff; font-weight: 700; font-size: 0.85rem; margin-bottom: 10px; }
    .steps.scrivener .step .num { background: #15b788; }
    .step h4 { font-size: 0.95rem; margin-bottom: 6px; }
    .step p { font-size: 0.8rem; color: #666; }
    .features-block { margin-bottom: 3rem; }
    .features-block:last-child { margin-bottom: 0; }
    .features-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(220px, 1fr)); gap: 20px; }
    .feature-card { background: #fff; border-radius: 12px; padding: 24px; border: 1px solid #eee; }
    .feature-card .icon { font-size: 1.8rem; margin-bottom: 0.6rem; }
    .feature-card h3 { font-size: 1rem; margin-bottom: 0.5rem; }
    .feature-card p { font-size: 0.85rem; color: #666; line-height: 1.6; }
    .bridge-banner { background: linear-gradient(135deg, #333 0%, #1a4a5e 100%); color: #feffff; border-radius: 16px; padding: 36px 32px; text-align: center; }
    .bridge-banner p { font-size: 1.15rem; font-weight: 700; margin-bottom: 1rem; }
    .bridge-banner ul { list-style: none; font-size: 0.9rem; opacity: 0.9; line-height: 2; }
    .cta-section { text-align: center; }
    .cta-app-pair { display: flex; justify-content: center; gap: 32px; flex-wrap: wrap; margin: 2rem 0 1.5rem; }
    .cta-app { text-align: center; max-width: 200px; }
    .cta-app img { width: 64px; height: 64px; border-radius: 22%; box-shadow: 0 4px 16px rgba(0,0,0,0.12); margin-bottom: 10px; }
    .cta-app h3 { font-size: 0.95rem; margin-bottom: 8px; }
    .store-badge { display: inline-block; background: #eee; color: #888; font-size: 0.75rem; font-weight: 700; padding: 6px 16px; border-radius: 100px; letter-spacing: 0.05em; }
    .cta-section .btn { display: inline-block; background: #1395ba; color: #fff; text-decoration: none; padding: 14px 32px; border-radius: 10px; font-weight: 700; margin: 6px; }
    .cta-section .btn.secondary { background: #15b788; }
    .cta-section .micro { margin-top: 1rem; font-size: 0.8rem; color: #999; }
    footer { text-align: center; padding: 32px 20px; border-top: 1px solid #eee; font-size: 0.85rem; color: #888; }
    footer a { color: #1395ba; text-decoration: none; }
    footer .links a { margin: 0 12px; }
    @media (max-width: 640px) {
      .hero h1 { font-size: 2rem; }
      .hero-icon { width: 80px; height: 80px; }
      .compare-arrow { width: 100%; justify-content: center; transform: rotate(90deg); margin: -8px 0; }
      .compare-box { max-width: 100%; }
      .pain-columns, .solution-paths { grid-template-columns: 1fr; }
    }

